// Format error notification message
const input = $input.first().json;

const errorMessage = `
🚨 **Vendor Sync Failed**

**Vendor:** ${input.vendor_name} (${input.vendor_id})
**Tier:** ${input.tier_used}
**Data Source:** ${input.data_source_type}
**Time:** ${new Date().toLocaleString()}

**Error Details:**
${input.errors && input.errors.length > 0 ? input.errors.map(e => `- ${e}`).join('\n') : 'Unknown error'}

**Suggested Actions:**
${getSuggestedActions(input)}

**Statistics:**
- Products Added: ${input.products_added || 0}
- Products Updated: ${input.products_updated || 0}
- Duration: ${input.duration_seconds || 0} seconds
`;

function getSuggestedActions(data) {
  const actions = [];

  if (data.tier_used === 1) {
    actions.push('- Check Google Drive/Dropbox/Sheets access permissions');
    actions.push('- Verify folder/file IDs in vendor config');
    actions.push('- Ensure data source structure matches expected format');
  } else if (data.tier_used === 2) {
    actions.push('- Verify Shopify store URL is accessible');
    actions.push('- Check if /products.json endpoint is available');
    actions.push('- Review rate limiting settings');
  } else if (data.tier_used === 3) {
    actions.push('- Check Zyte API credits and status');
    actions.push('- Verify Gemini API key and quota');
    actions.push('- Review website structure for changes');
    actions.push('- Consider updating AI extraction prompts');
  }

  actions.push('- Review sync_log table for detailed error information');
  actions.push('- Consider manual intervention or tier fallback');

  return actions.join('\n');
}

return [{
  json: {
    ...input,
    error_message: errorMessage,
    notification_type: 'vendor_sync_failed',
    severity: 'high',
    timestamp: new Date().toISOString()
  }
}];

// Log notification status
const input = $input.first().json;

return [{
  json: {
    vendor_id: input.vendor_id,
    vendor_name: input.vendor_name,
    notification_sent: true,
    notification_timestamp: new Date().toISOString(),
    slack_sent: $node['Send Slack Notification'].json ? true : false,
    email_sent: $node['Send Email Notification'].json ? true : false
  }
}];
